#include <bits/stdc++.h>
using namespace std;
using ll = long long;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    cin >> N;
    vector<int> a(N + 1);
    int maxA = 0;
    for (int i = 1; i <= N; ++i) {
        cin >> a[i];
        if (a[i] > maxA) maxA = a[i];
    }
    int maxV = maxA + N;                 // 足够大的上界
    vector<vector<int>> bucket(maxV + 1);
    for (int i = 1; i <= N; ++i) {
        bucket[a[i]].push_back(i);
    }

    vector<int> preR(N + 2, 0);          // 上一轮 (v-1) 的 R 值
    vector<int> bestR(N + 1, 0);        // 每个左端点已覆盖的最大右端点
    for (int i = 1; i <= N; ++i) bestR[i] = i - 1;

    vector<int> active;                 // 上一轮非零的索引
    ll ans = 0;
    int done = 0;                       // 已经覆盖到 N 的左端点个数
    vector<bool> finished(N + 1, false);

    for (int v = 1; v <= maxV; ++v) {
        vector<int> curR(N + 2, 0);
        vector<int> curActive;

        // 初始：a[i] == v 的单个元素
        for (int i : bucket[v]) {
            curR[i] = i;
            curActive.push_back(i);
            if (i > bestR[i]) {
                ans += (ll)v * (i - bestR[i]);
                bestR[i] = i;
                if (bestR[i] == N && !finished[i]) {
                    finished[i] = true;
                    ++done;
                }
            }
        }

        // 递推：由 v-1 扩展得到 v
        for (int i : active) {
            int mid = preR[i];
            if (mid == 0) continue;
            int nxt = mid + 1;
            if (nxt <= N && preR[nxt] != 0) {
                int newR = preR[nxt];
                curR[i] = newR;
                curActive.push_back(i);
                if (newR > bestR[i]) {
                    ans += (ll)v * (newR - bestR[i]);
                    bestR[i] = newR;
                    if (bestR[i] == N && !finished[i]) {
                        finished[i] = true;
                        ++done;
                    }
                }
            }
        }

        preR.swap(curR);
        active.swap(curActive);
        if (done == N) break;           // 所有左端点都已完全覆盖
    }

    cout << ans << '\n';
    return 0;
}
